const item = $input.first();
const body = item.json.body || item.json;

function cleanString(value) {
  return String(value || '').trim();
}

function normalizeMember(member, index) {
  const techStack = Array.isArray(member.tech_stack)
    ? member.tech_stack
    : Array.isArray(member.techStack)
      ? member.techStack
      : cleanString(member.tech_stack || member.techStack).split(',').map(v => v.trim()).filter(Boolean);

  const softSkills = Array.isArray(member.soft_skills)
    ? member.soft_skills
    : Array.isArray(member.softSkills)
      ? member.softSkills
      : cleanString(member.soft_skills || member.softSkills).split(',').map(v => v.trim()).filter(Boolean);

  return {
    member_id: member.member_id || `member_${index + 1}`,
    name: cleanString(member.name) || `팀원 ${index + 1}`,
    preferred_role: cleanString(member.preferred_role || member.role),
    github_url: cleanString(member.github_url || member.githubUrl),
    tech_stack: techStack,
    soft_skills: softSkills,
    notes: cleanString(member.notes),
  };
}

const members = Array.isArray(body.members) ? body.members.map(normalizeMember) : [];

const projectTopic = cleanString(body.project_topic || body.projectTopic || body.title);
const projectRepoUrl = cleanString(body.project_repo_url || body.projectRepoUrl || body.repo_url || body.repoUrl);
const deadline = cleanString(body.deadline || body.due_date || body.dueDate);
const extraContext = cleanString(body.extra_context || body.extraContext || body.context);

if (!projectTopic) {
  return [{ json: { ok: false, error: 'project_topic이 비어 있습니다.' } }];
}
if (!projectRepoUrl) {
  return [{ json: { ok: false, error: 'project_repo_url이 비어 있습니다.' } }];
}
if (!members.length) {
  return [{ json: { ok: false, error: 'members 배열이 비어 있습니다.' } }];
}
const missingGithub = members.filter(m => !m.github_url);
if (missingGithub.length) {
  return [{ json: { ok: false, error: `GitHub 링크가 없는 팀원이 있습니다: ${missingGithub.map(m => m.name).join(', ')}` } }];
}

const projectId = cleanString(body.project_id || body.projectId)
  || projectTopic.toLowerCase()
    .replace(/https?:\/\//g, '')
    .replace(/[^a-z0-9가-힣]+/gi, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 60)
  || `project-${Date.now()}`;

return [{
  json: {
    ok: true,
    mode: 'init',
    project: {
      project_id: projectId,
      project_topic: projectTopic,
      deadline,
      project_repo_url: projectRepoUrl,
      extra_context: extraContext,
      source: 'form.html',
      created_at: new Date().toISOString(),
    },
    members,
  }
}];

const source = $input.first().json;
return source.members.map(member => ({
  json: {
    project: source.project,
    member,
    analyzer_request: {
      member,
      github_url: member.github_url,
      max_repos: 10,
      include_readme: true,
      include_file_tree: true,
      include_contribution: true,
    }
  }
}));

const analyzedItems = $input.all().map(item => item.json);
const firstProject = analyzedItems[0]?.project || analyzedItems[0]?.input_project || {};

const memberAnalyses = analyzedItems.map((item, index) => {
  const member = item.member || item.request?.member || item.input?.member || {};
  const analysis = item.analysis || item.github_analysis || item;
  return {
    member_id: member.member_id || `member_${index + 1}`,
    name: member.name || analysis?.user?.username || `팀원 ${index + 1}`,
    preferred_role: member.preferred_role || '',
    declared_tech_stack: member.tech_stack || [],
    soft_skills: member.soft_skills || [],
    github_url: member.github_url || analysis?.input?.github_profile_url || '',
    github_analysis: analysis,
  };
});

return [{
  json: {
    project: firstProject,
    member_analyses: memberAnalyses,
  }
}];

const data = $input.first().json;
const project = data.project;
const memberAnalyses = data.member_analyses;

const compactMembers = memberAnalyses.map(m => {
  const ga = m.github_analysis || {};
  return {
    name: m.name,
    preferred_role: m.preferred_role,
    declared_tech_stack: m.declared_tech_stack,
    soft_skills: m.soft_skills,
    github_url: m.github_url,
    github_summary: ga.summary || {},
    github_user: ga.user || {},
    repositories: (ga.repositories || []).slice(0, 10).map(repo => ({
      repo_name: repo.repo_name,
      html_url: repo.html_url,
      description: repo.description,
      updated_at: repo.updated_at,
      pushed_at: repo.pushed_at,
      main_language: repo.main_language,
      languages: repo.languages,
      framework_library_analysis: repo.framework_library_analysis,
      contribution: repo.contribution ? {
        commit_count_sampled: repo.contribution.commit_count_sampled,
        total_additions_sampled: repo.contribution.total_additions_sampled,
        total_deletions_sampled: repo.contribution.total_deletions_sampled,
        top_touched_files: repo.contribution.top_touched_files,
        recent_commits: repo.contribution.recent_commits,
      } : {}
    }))
  };
});

const prompt = `
너는 대학생 팀 프로젝트의 역할 분담을 설계하는 PM/테크리드야.
아래 프로젝트 정보, 팀원 자기기입 정보, GitHub 최근 10개 레포 분석 JSON을 함께 보고 역할을 배정해줘.

[중요 원칙]
1. GitHub 분석 결과만으로 단정하지 말고, 본인이 입력한 희망 역할/기술스택/소프트스킬과 함께 판단해.
2. 역할은 Frontend, Backend, AI/ML, Data, DevOps, PM/기획, 문서/발표, QA 중에서 필요하면 복수 배정해.
3. 각 팀원별로 "왜 이 역할이 맞는지"를 GitHub 근거와 입력 근거로 설명해.
4. 프로젝트 레포 ${project.project_repo_url} 기준으로 초기 태스크를 To Do / In Progress / Review / Done 칸반 형태로 제안해.
5. 이후 진행 보고서와 GitHub 레포 분석 결과가 들어오면 계속 업데이트할 수 있도록 Markdown 문서 구조를 만들어줘.
6. 응답은 반드시 JSON만 반환해. Markdown 설명을 바깥에 붙이지 마.

[출력 JSON 형식]
{
  "project_summary": "...",
  "role_assignments": [
    {
      "member_name": "...",
      "primary_role": "...",
      "secondary_roles": ["..."],
      "reason": "...",
      "evidence": {
        "declared": ["..."],
        "github": ["..."]
      },
      "recommended_tasks": ["..."],
      "risk_or_gap": "..."
    }
  ],
  "kanban": {
    "todo": [{"title":"...", "assignee":"...", "reason":"...", "estimated_effort":"..."}],
    "in_progress": [],
    "review": [],
    "done": []
  },
  "workflow_policy": {
    "progress_report_format": "...",
    "github_sync_policy": "...",
    "feedback_loop_rule": "..."
  },
  "markdown_flow": "# ProjectTracker Flow\\n..."
}

[프로젝트 정보]
${JSON.stringify(project, null, 2)}

[팀원 GitHub 분석]
${JSON.stringify(compactMembers, null, 2)}
`;

return [{
  json: {
    project,
    member_analyses: memberAnalyses,
    prompt,
  }
}];

const original = $('Prepare Role Assignment Prompt').first().json;
const response = $input.first().json;

function getContent(res) {
  return res?.choices?.[0]?.message?.content || '';
}

function stripFence(text) {
  text = String(text || '').trim();
  if (text.startsWith('```json')) text = text.slice(7).trim();
  else if (text.startsWith('```')) text = text.slice(3).trim();
  if (text.endsWith('```')) text = text.slice(0, -3).trim();
  return text;
}

let parsed;
const content = getContent(response);
try {
  parsed = JSON.parse(stripFence(content));
} catch (error) {
  parsed = {
    project_summary: 'AI 응답 JSON 파싱 실패',
    raw_content: content,
    parse_error: String(error),
    markdown_flow: `# ProjectTracker Flow\n\n## Raw Upstage Response\n\n${content}`
  };
}

const markdown = parsed.markdown_flow || `# ProjectTracker Flow

## 프로젝트
${original.project.project_topic}

## 역할 분담 결과
\`\`\`json
${JSON.stringify(parsed, null, 2)}
\`\`\`
`;

return [{
  json: {
    ok: true,
    mode: 'init',
    project: original.project,
    role_assignment: parsed,
    member_analyses: original.member_analyses,
    markdown_flow: markdown,
  }
}];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const baseDir = process.env.PROJECT_TRACKER_FLOW_DIR || '/data/projectTracker/flows';
fs.mkdirSync(baseDir, { recursive: true });

const projectId = data.project.project_id;
const flowPath = path.join(baseDir, `${projectId}.md`);
const analysisPath = path.join(baseDir, `${projectId}.analysis.json`);

fs.writeFileSync(flowPath, data.markdown_flow, 'utf8');
fs.writeFileSync(analysisPath, JSON.stringify({
  project: data.project,
  role_assignment: data.role_assignment,
  member_analyses: data.member_analyses,
}, null, 2), 'utf8');

return [{
  json: {
    ok: true,
    message: '초기 역할 분담과 flow.md 저장 완료',
    project: data.project,
    role_assignment: data.role_assignment,
    saved_files: {
      flow_md: flowPath,
      analysis_json: analysisPath,
    }
  }
}];

const body = $input.first().json.body || $input.first().json;

function clean(value) { return String(value || '').trim(); }

const projectId = clean(body.project_id || body.projectId);
const projectRepoUrl = clean(body.project_repo_url || body.projectRepoUrl || body.repo_url || body.repoUrl);
const progressReport = clean(body.progress_report || body.progressReport || body.report);
const meetingNotes = clean(body.meeting_notes || body.meetingNotes);

if (!projectId) return [{ json: { ok: false, error: 'project_id가 필요합니다.' } }];
if (!projectRepoUrl) return [{ json: { ok: false, error: 'project_repo_url이 필요합니다.' } }];
if (!progressReport && !meetingNotes) return [{ json: { ok: false, error: '진행 보고서 또는 회의록이 필요합니다.' } }];

return [{
  json: {
    ok: true,
    mode: 'progress',
    project_id: projectId,
    project_repo_url: projectRepoUrl,
    progress_report: progressReport,
    meeting_notes: meetingNotes,
    created_at: new Date().toISOString(),
  }
}];

const fs = require('fs');
const path = require('path');
const progress = $('Normalize Progress Payload').first().json;
const repoAnalysis = $input.first().json;

const baseDir = process.env.PROJECT_TRACKER_FLOW_DIR || '/data/projectTracker/flows';
const flowPath = path.join(baseDir, `${progress.project_id}.md`);

let previousFlow = '';
try {
  previousFlow = fs.readFileSync(flowPath, 'utf8');
} catch (error) {
  previousFlow = '# ProjectTracker Flow\n\n이전 flow.md를 찾지 못했습니다. 이번 진행 보고서를 기준으로 새 흐름을 만듭니다.\n';
}

return [{
  json: {
    progress,
    repo_analysis: repoAnalysis,
    flow_path: flowPath,
    previous_flow: previousFlow,
  }
}];

const data = $input.first().json;
const progress = data.progress;

const prompt = `
너는 ProjectTracker의 진행 관리 AI야.
아래 기존 flow.md, 새 진행 보고서, 프로젝트 GitHub 레포 분석 결과를 비교해서 다음 액션을 제안해줘.

[해야 할 일]
1. 진행 보고서와 GitHub 활동이 일치하는지 확인해.
2. 완료된 일, 지연된 일, 새로 생긴 일을 구분해.
3. 칸반 상태 변경안을 제안해.
4. 팀원별 다음 할 일을 재배정해.
5. 기존 flow.md 뒤에 이어붙일 Markdown 업데이트 섹션을 작성해.
6. 응답은 반드시 JSON만 반환해.

[출력 JSON 형식]
{
  "progress_summary": "...",
  "consistency_check": {
    "matched": ["..."],
    "mismatch_or_risk": ["..."]
  },
  "kanban_updates": [
    {"task":"...", "from":"...", "to":"...", "reason":"..."}
  ],
  "next_actions": [
    {"assignee":"...", "task":"...", "priority":"high|medium|low", "reason":"..."}
  ],
  "feedback": "...",
  "markdown_append": "## Progress Update - ..."
}

[기존 flow.md]
${data.previous_flow}

[새 진행 보고서]
${progress.progress_report}

[회의록]
${progress.meeting_notes}

[프로젝트 GitHub 레포 분석]
${JSON.stringify(data.repo_analysis, null, 2)}
`;

return [{ json: { ...data, prompt } }];

const fs = require('fs');
const base = $('Prepare Progress Feedback Prompt').first().json;
const response = $input.first().json;

function getContent(res) {
  return res?.choices?.[0]?.message?.content || '';
}
function stripFence(text) {
  text = String(text || '').trim();
  if (text.startsWith('```json')) text = text.slice(7).trim();
  else if (text.startsWith('```')) text = text.slice(3).trim();
  if (text.endsWith('```')) text = text.slice(0, -3).trim();
  return text;
}

let parsed;
const content = getContent(response);
try {
  parsed = JSON.parse(stripFence(content));
} catch (error) {
  parsed = {
    progress_summary: 'AI 응답 JSON 파싱 실패',
    raw_content: content,
    parse_error: String(error),
    markdown_append: `\n\n## Progress Update - ${new Date().toISOString()}\n\n${content}\n`
  };
}

const append = parsed.markdown_append || `\n\n## Progress Update - ${new Date().toISOString()}\n\n\`\`\`json\n${JSON.stringify(parsed, null, 2)}\n\`\`\`\n`;
fs.appendFileSync(base.flow_path, `\n\n${append}`, 'utf8');

return [{
  json: {
    ok: true,
    message: '진행 피드백 생성 및 flow.md 업데이트 완료',
    project_id: base.progress.project_id,
    feedback: parsed,
    saved_files: {
      flow_md: base.flow_path
    }
  }
}];
